@table = external hidden constant [2 x ptr], align 16

define i1 @pr93017(i64 %idx) {
  %gep = getelementptr inbounds [2 x ptr], ptr @table, i64 0, i64 %idx
  %v = load ptr, ptr %gep, align 8
  %cmp = icmp ne ptr %v, null
  ret i1 %cmp
}

